1	import { Injectable, NgZone, OnDestroy } from '@angular/core';
2	import { Router } from '@angular/router';
3	import { BehaviorSubject, Observable } from 'rxjs';
4	import { CryptoService, EncryptedPayload } from './crypto.service';
5	
6	// =====================================================
7	// Auth Types
8	// =====================================================
9	
10	export type UserRole = 'admin' | 'resident' | 'compliance' | 'analyst';
11	
12	export interface RoleCredentials {
13	  admin:      string;
14	  resident:   string;
15	  compliance: string;
16	  analyst:    string;
17	}
18	
19	export interface AuthState {
20	  role:        UserRole | null;
21	  isLocked:    boolean;
22	  isLoggedIn:  boolean;
23	}
24	
25	// =====================================================
26	// AuthService
27	// In-memory session only — role NEVER written to LocalStorage
28	// for security enforcement. Only hp_last_role (UX hint) stored.
29	// =====================================================
30	
31	const DEFAULT_PASSWORDS: RoleCredentials = {
32	  admin:      'harborpoint2024',
33	  resident:   'harborpoint2024',
34	  compliance: 'harborpoint2024',
35	  analyst:    'harborpoint2024',
36	};
37	
38	const LS_LAST_ROLE = 'hp_last_role';
39	const LS_CRYPTO_SALT = 'hp_crypto_salt';
40	const INACTIVITY_MS = 30 * 60 * 1000; // 30 minutes
41	
42	// Validation token storage key (stores encrypted test payload)
43	const LS_VALIDATION_PREFIX = 'hp_vt_';
44	
45	@Injectable({ providedIn: 'root' })
46	export class AuthService implements OnDestroy {
47	
48	  private _state$ = new BehaviorSubject<AuthState>({
49	    role: null,
50	    isLocked: false,
51	    isLoggedIn: false,
52	  });
53	
54	  readonly state$: Observable<AuthState> = this._state$.asObservable();
55	
56	  private _currentUserId: number | null = null;
57	  private inactivityTimer: ReturnType<typeof setTimeout> | null = null;
58	  private activityListeners: (() => void)[] = [];
59	
60	  private static readonly USER_ID_MAP: Record<string, number> = {
61	    admin: 1, resident: 2, compliance: 3, analyst: 4,
62	  };
63	
64	  constructor(
65	    private crypto: CryptoService,
66	    private router: Router,
67	    private ngZone: NgZone,
68	  ) {
69	    this.setupActivityTracking();
70	  }
71	
72	  // --------------------------------------------------
73	  // Username + Password Login
74	  // --------------------------------------------------
75	
76	  private static readonly VALID_USERNAMES: Record<string, UserRole> = {
77	    admin:      'admin',
78	    resident:   'resident',
79	    compliance: 'compliance',
80	    analyst:    'analyst',
81	  };
82	
83	  async login(username: string, password: string): Promise<{ success: boolean; error?: string }> {
84	    const role = AuthService.VALID_USERNAMES[username.trim().toLowerCase()];
85	    if (!role) {
86	      return { success: false, error: 'Invalid username or password' };
87	    }
88	    const ok = await this.selectRole(role, password);
89	    if (!ok) {
90	      return { success: false, error: 'Invalid username or password' };
91	    }
92	    this._currentUserId = AuthService.USER_ID_MAP[role] ?? null;
93	    return { success: true };
94	  }
95	
96	  // --------------------------------------------------
97	  // Role Selection (internal / re-auth)
98	  // --------------------------------------------------
99	
100	  async selectRole(role: UserRole, password: string): Promise<boolean> {
101	    const validationKey = LS_VALIDATION_PREFIX + role;
102	    const stored = localStorage.getItem(validationKey);
103	
104	    let passwordOk = false;
105	
106	    if (stored) {
107	      // Validate against existing encrypted token
108	      try {
109	        const payload: EncryptedPayload = JSON.parse(stored);
110	        passwordOk = await this.crypto.validatePassword(password, payload);
111	      } catch {
112	        passwordOk = false;
113	      }
114	    } else {
115	      // First run: check against default password, then store validation token
116	      passwordOk = password === DEFAULT_PASSWORDS[role];
117	      if (passwordOk) {
118	        const token = await this.crypto.createValidationToken(password);
119	        localStorage.setItem(validationKey, JSON.stringify(token));
120	      }
121	    }
122	
123	    if (!passwordOk) return false;
124	
125	    // Derive session encryption key from password
126	    let saltB64 = localStorage.getItem(LS_CRYPTO_SALT);
127	    let salt: Uint8Array;
128	    if (saltB64) {
129	      salt = new Uint8Array(this.crypto.base64ToBuffer(saltB64));
130	    } else {
131	      salt = this.crypto.generateSalt();
132	      saltB64 = this.crypto.bufferToBase64(salt);
133	      localStorage.setItem(LS_CRYPTO_SALT, saltB64);
134	    }
135	    const sessionKey = await this.crypto.deriveKey(password, salt);
136	    this.crypto.setSessionKey(sessionKey);
137	
138	    this._currentUserId = AuthService.USER_ID_MAP[role] ?? null;
139	
140	    // Persist UX hint only (not used for guard checks)
141	    localStorage.setItem(LS_LAST_ROLE, role);
142	
143	    this._state$.next({
144	      role,
145	      isLocked: false,
146	      isLoggedIn: true,
147	    });
148	
149	    this.resetInactivityTimer();
150	    return true;
151	  }
152	
153	  // --------------------------------------------------
154	  // Session Lock
155	  // --------------------------------------------------
156	
157	  lockSession(): void {
158	    this._currentUserId = null;
159	    this.crypto.setSessionKey(null);
160	    this._state$.next({
161	      role: this._state$.value.role,
162	      isLocked: true,
163	      isLoggedIn: false,
164	    });
165	    this.clearInactivityTimer();
166	    this.router.navigate(['/login']);
167	  }
168	
169	  // --------------------------------------------------
170	  // Re-authentication (for anomaly re-auth modal)
171	  // --------------------------------------------------
172	
173	  async reAuthenticate(password: string): Promise<boolean> {
174	    const role = this._state$.value.role;
175	    if (!role) return false;
176	    return this.selectRole(role, password);
177	  }
178	
179	  // --------------------------------------------------
180	  // Role Checks — used in guards and service methods
181	  // --------------------------------------------------
182	
183	  hasRole(role: UserRole): boolean {
184	    const state = this._state$.value;
185	    return state.isLoggedIn && !state.isLocked && state.role === role;
186	  }
187	
188	  hasAnyRole(...roles: UserRole[]): boolean {
189	    const state = this._state$.value;
190	    return state.isLoggedIn && !state.isLocked && state.role !== null && roles.includes(state.role);
191	  }
192	
193	  getCurrentRole(): UserRole | null {
194	    return this._state$.value.role;
195	  }
196	
197	  getCurrentUserId(): number | null {
198	    return this._currentUserId;
199	  }
200	
201	  isLoggedIn(): boolean {
202	    return this._state$.value.isLoggedIn && !this._state$.value.isLocked;
203	  }
204	
205	  // --------------------------------------------------
206	  // UX Helpers
207	  // --------------------------------------------------
208	
209	  getLastRole(): UserRole | null {
210	    const stored = localStorage.getItem(LS_LAST_ROLE);
211	    if (stored && ['admin', 'resident', 'compliance', 'analyst'].includes(stored)) {
212	      return stored as UserRole;
213	    }
214	    return null;
215	  }
216	
217	  logout(): void {
218	    this._currentUserId = null;
219	    this.crypto.setSessionKey(null);
220	    this._state$.next({ role: null, isLocked: false, isLoggedIn: false });
221	    this.clearInactivityTimer();
222	    this.router.navigate(['/login']);
223	  }
224	
225	  // --------------------------------------------------
226	  // Inactivity Timer
227	  // --------------------------------------------------
228	
229	  private setupActivityTracking(): void {
230	    const events = ['mousedown', 'keydown', 'touchstart', 'scroll'];
231	    const handler = () => this.ngZone.run(() => this.resetInactivityTimer());
232	
233	    this.ngZone.runOutsideAngular(() => {
234	      for (const event of events) {
235	        document.addEventListener(event, handler, { passive: true });
236	        this.activityListeners.push(() =>
237	          document.removeEventListener(event, handler),
238	        );
239	      }
240	    });
241	  }
242	
243	  resetInactivityTimer(): void {
244	    this.clearInactivityTimer();
245	    if (!this._state$.value.isLoggedIn) return;
246	
247	    this.inactivityTimer = setTimeout(() => {
248	      this.ngZone.run(() => this.lockSession());
249	    }, INACTIVITY_MS);
250	  }
251	
252	  private clearInactivityTimer(): void {
253	    if (this.inactivityTimer !== null) {
254	      clearTimeout(this.inactivityTimer);
255	      this.inactivityTimer = null;
256	    }
257	  }
258	
259	  getInactivityTimer(): ReturnType<typeof setTimeout> | null {
260	    return this.inactivityTimer;
261	  }
262	
263	  // --------------------------------------------------
264	  // Password Change
265	  // --------------------------------------------------
266	
267	  async changePassword(role: UserRole, currentPassword: string, newPassword: string): Promise<boolean> {
268	    const validationKey = LS_VALIDATION_PREFIX + role;
269	    const stored = localStorage.getItem(validationKey);
270	
271	    let currentOk = false;
272	    if (stored) {
273	      const payload: EncryptedPayload = JSON.parse(stored);
274	      currentOk = await this.crypto.validatePassword(currentPassword, payload);
275	    } else {
276	      currentOk = currentPassword === DEFAULT_PASSWORDS[role];
277	    }
278	
279	    if (!currentOk) return false;
280	
281	    const newToken = await this.crypto.createValidationToken(newPassword);
282	    localStorage.setItem(validationKey, JSON.stringify(newToken));
283	    return true;
284	  }
285	
286	  ngOnDestroy(): void {
287	    this.clearInactivityTimer();
288	    this.activityListeners.forEach(fn => fn());
289	  }
290	}
291	
