1	import { Injectable } from '@angular/core';
2	import { DbService, Building, Unit, Room, Occupancy, Resident } from './db.service';
3	import { AuditAction, AuditService } from './audit.service';
4	import { AuthService } from './auth.service';
5	import DOMPurify from 'dompurify';
6	
7	export enum ReasonCode {
8	  MOVE_IN_NEW        = 'MOVE_IN_NEW',
9	  TRANSFER           = 'TRANSFER',
10	  LEASE_START        = 'LEASE_START',
11	  MOVE_OUT_VOLUNTARY = 'MOVE_OUT_VOLUNTARY',
12	  MOVE_OUT_EVICTION  = 'MOVE_OUT_EVICTION',
13	  LEASE_END          = 'LEASE_END',
14	  ADMINISTRATIVE     = 'ADMINISTRATIVE',
15	}
16	
17	/** Union of enum values + string for backward-compatibility with existing DB records. */
18	export type MoveReasonCode = ReasonCode | string;
19	
20	@Injectable({ providedIn: 'root' })
21	export class PropertyService {
22	
23	  constructor(
24	    private db: DbService,
25	    private audit: AuditService,
26	    private authService: AuthService,
27	  ) {}
28	
29	  private requireRole(...allowedRoles: string[]): void {
30	    const current = this.authService.getCurrentRole();
31	    if (!current || !allowedRoles.includes(current)) {
32	      throw new Error(`Unauthorized: requires role ${allowedRoles.join(' or ')}`);
33	    }
34	  }
35	
36	  // --------------------------------------------------
37	  // Buildings
38	  // --------------------------------------------------
39	
40	  async getBuildings(): Promise<Building[]> {
41	    return this.db.buildings.toArray();
42	  }
43	
44	  async getBuilding(id: number): Promise<Building | undefined> {
45	    return this.db.buildings.get(id);
46	  }
47	
48	  async createBuilding(data: Omit<Building, 'id' | 'createdAt' | 'updatedAt'>, actorId: number, actorRole: string): Promise<Building> {
49	    this.requireRole('admin');
50	    const now = new Date();
51	    const id = await this.db.buildings.add({
52	      ...data,
53	      name: DOMPurify.sanitize(data.name),
54	      address: DOMPurify.sanitize(data.address),
55	      createdAt: now,
56	      updatedAt: now,
57	    });
58	    const building = await this.db.buildings.get(id);
59	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'building', id, undefined, building);
60	    return building!;
61	  }
62	
63	  async updateBuilding(id: number, data: Partial<Building>, actorId: number, actorRole: string): Promise<void> {
64	    this.requireRole('admin');
65	    const before = await this.db.buildings.get(id);
66	    await this.db.buildings.update(id, { ...data, updatedAt: new Date() });
67	    const after = await this.db.buildings.get(id);
68	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'building', id, before, after);
69	  }
70	
71	  // --------------------------------------------------
72	  // Units
73	  // --------------------------------------------------
74	
75	  async getUnits(buildingId?: number): Promise<Unit[]> {
76	    if (buildingId !== undefined) {
77	      return this.db.units.where('buildingId').equals(buildingId).toArray();
78	    }
79	    return this.db.units.toArray();
80	  }
81	
82	  async createUnit(data: Omit<Unit, 'id' | 'createdAt' | 'updatedAt'>, actorId: number, actorRole: string): Promise<Unit> {
83	    this.requireRole('admin');
84	    const now = new Date();
85	    const id = await this.db.units.add({ ...data, createdAt: now, updatedAt: now });
86	    const unit = await this.db.units.get(id);
87	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'unit', id, undefined, unit);
88	    return unit!;
89	  }
90	
91	  async updateUnit(id: number, data: Partial<Unit>, actorId: number, actorRole: string): Promise<void> {
92	    this.requireRole('admin');
93	    const before = await this.db.units.get(id);
94	    await this.db.units.update(id, { ...data, updatedAt: new Date() });
95	    const after = await this.db.units.get(id);
96	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'unit', id, before, after);
97	  }
98	
99	  // --------------------------------------------------
100	  // Rooms
101	  // --------------------------------------------------
102	
103	  async getRooms(unitId?: number): Promise<Room[]> {
104	    if (unitId !== undefined) {
105	      return this.db.rooms.where('unitId').equals(unitId).toArray();
106	    }
107	    return this.db.rooms.toArray();
108	  }
109	
110	  async createRoom(data: Omit<Room, 'id' | 'createdAt' | 'updatedAt'>, actorId: number, actorRole: string): Promise<Room> {
111	    this.requireRole('admin');
112	    const now = new Date();
113	    const id = await this.db.rooms.add({ ...data, createdAt: now, updatedAt: now });
114	    const room = await this.db.rooms.get(id);
115	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'room', id, undefined, room);
116	    return room!;
117	  }
118	
119	  async updateRoom(id: number, data: Partial<Room>, actorId: number, actorRole: string): Promise<void> {
120	    this.requireRole('admin');
121	    const before = await this.db.rooms.get(id);
122	    await this.db.rooms.update(id, { ...data, updatedAt: new Date() });
123	    const after = await this.db.rooms.get(id);
124	    this.audit.log(AuditAction.RULE_CHANGED, actorId, actorRole, 'room', id, before, after);
125	  }
126	
127	  // --------------------------------------------------
128	  // Occupancy — Move In
129	  // Only one active occupancy per resident at a time.
130	  // --------------------------------------------------
131	
132	  async moveIn(params: {
133	    residentId: number;
134	    roomId: number;
135	    effectiveFrom: Date;
136	    reasonCode: MoveReasonCode;
137	    actorId: number;
138	    actorRole: string;
139	  }): Promise<Occupancy> {
140	    this.requireRole('admin');
141	    // Enforce: one active occupancy per resident
142	    const existing = await this.db.occupancies
143	      .filter(o => o.residentId === params.residentId && o.status === 'active')
144	      .first();
145	
146	    if (existing) {
147	      throw new Error('RESIDENT_ALREADY_HAS_ACTIVE_OCCUPANCY');
148	    }
149	
150	    const id = await this.db.occupancies.add({
151	      residentId:    params.residentId,
152	      roomId:        params.roomId,
153	      effectiveFrom: params.effectiveFrom,
154	      reasonCode:    params.reasonCode,
155	      status:        'active',
156	      createdAt:     new Date(),
157	    });
158	
159	    const occupancy = await this.db.occupancies.get(id);
160	
161	    this.audit.log(
162	      AuditAction.MOVE_IN,
163	      params.actorId,
164	      params.actorRole,
165	      'occupancy',
166	      id,
167	      undefined,
168	      occupancy,
169	    );
170	
171	    return occupancy!;
172	  }
173	
174	  // --------------------------------------------------
175	  // Occupancy — Move Out
176	  // --------------------------------------------------
177	
178	  async moveOut(params: {
179	    residentId: number;
180	    effectiveTo: Date;
181	    reasonCode: MoveReasonCode;
182	    actorId: number;
183	    actorRole: string;
184	  }): Promise<void> {
185	    this.requireRole('admin');
186	    const active = await this.db.occupancies
187	      .filter(o => o.residentId === params.residentId && o.status === 'active')
188	      .first();
189	
190	    if (!active?.id) throw new Error('NO_ACTIVE_OCCUPANCY');
191	
192	    const before = { ...active };
193	    await this.db.occupancies.update(active.id, {
194	      effectiveTo: params.effectiveTo,
195	      reasonCode:  params.reasonCode,
196	      status:      'ended',
197	    });
198	    const after = await this.db.occupancies.get(active.id);
199	
200	    this.audit.log(
201	      AuditAction.MOVE_OUT,
202	      params.actorId,
203	      params.actorRole,
204	      'occupancy',
205	      active.id,
206	      before,
207	      after,
208	    );
209	  }
210	
211	  async getActiveOccupancy(residentId: number): Promise<Occupancy | undefined> {
212	    return this.db.occupancies
213	      .filter(o => o.residentId === residentId && o.status === 'active')
214	      .first();
215	  }
216	
217	  async getOccupancyHistory(residentId: number): Promise<Occupancy[]> {
218	    return this.db.occupancies
219	      .filter(o => o.residentId === residentId)
220	      .sortBy('effectiveFrom');
221	  }
222	
223	  // --------------------------------------------------
224	  // Room Occupants
225	  // --------------------------------------------------
226	
227	  async getRoomOccupants(roomId: number): Promise<{ occupancy: Occupancy; resident: Resident }[]> {
228	    const activeOccupancies = await this.db.occupancies
229	      .filter(o => o.roomId === roomId && o.status === 'active')
230	      .toArray();
231	
232	    const results = await Promise.all(
233	      activeOccupancies.map(async occ => {
234	        const resident = await this.db.residents.get(occ.residentId);
235	        return resident ? { occupancy: occ, resident } : null;
236	      }),
237	    );
238	
239	    return results.filter(
240	      (r): r is { occupancy: Occupancy; resident: Resident } => r !== null,
241	    );
242	  }
243	}
244	
