82	  }
83	
84	  // --------------------------------------------------
85	  // getPendingReview — all pending docs (compliance queue)
86	  // --------------------------------------------------
87	
88	  async getPendingReview(): Promise<HpDocument[]> {
89	    this.requireRole('compliance', 'admin');
90	    return this.db.documents
91	      .filter(d => d.status === 'pending_review' && !d.hidden)
92	      .toArray();
93	  }
94	
95	  // --------------------------------------------------
96	  // uploadDocument
97	  // Validates type / size / per-resident count, then
98	  // SHA-256 hashes the file (encrypted at rest),
99	  // encrypts file data, stores with pending_review.
100	  // --------------------------------------------------
101	
102	  async uploadDocument(
103	    residentId:      number,
104	    file:            File,
105	    consentRecordId: number,
106	    actorId:         number,
107	    actorRole:       string,
108	  ): Promise<HpDocument> {
109	
110	    this.requireRole('resident', 'admin');
111	
112	    // ── Consent validation ─────────────────────────
113	    const consentStatus = await this.getConsentStatus(residentId);
114	    if (!consentStatus.granted) {
115	      throw new Error('Upload rejected: resident has not granted document consent');
116	    }
117	    const consentRecord = await this.db.consentRecords.get(consentRecordId);
118	    if (!consentRecord || consentRecord.residentId !== residentId || consentRecord.action !== 'granted') {
119	      throw new Error('Upload rejected: invalid or mismatched consent record');
120	    }
121	
122	    // ── Content policy check on file name ────────────
123	    const policyResult = await this.contentPolicy.evaluate(file.name);
124	    if (policyResult.action === 'block') {
125	      throw new Error('Document upload blocked by content safety policy');
126	    }
127	
128	    // ── Validation ──────────────────────────────────
129	    if (!this.ALLOWED_MIME_TYPES.includes(file.type as never)) {
130	      throw new Error('INVALID_FILE_TYPE');
131	    }
132	    if (file.size > this.MAX_FILE_SIZE_BYTES) {
133	      throw new Error('FILE_TOO_LARGE');
134	    }
135	    const existingCount = await this.db.documents
136	      .where('residentId').equals(residentId)
137	      .count();
138	    if (existingCount >= this.MAX_FILES_PER_RESIDENT) {
139	      throw new Error('MAX_FILES_REACHED');
140	    }
141	
142	    const buffer = await file.arrayBuffer();
143	    const key    = this.getKey();
144	
145	    // ── SHA-256 hash — encrypted at rest ────────────
146	    const rawHash = await this.crypto.hashFile(buffer);
147	    const { ciphertext: hc, iv: hiv } = await this.crypto.encryptRaw(rawHash, key);
148	    const fileHash = `${hc}.${hiv}`;
149	
150	    // ── File content — base64, encrypted at rest ────
151	    const rawBase64 = this.crypto.bufferToBase64(buffer);
152	    const { ciphertext: dc, iv: div } = await this.crypto.encryptRaw(rawBase64, key);
153	    const fileData = `${dc}.${div}`;
154	
155	    const now = new Date();
156	    const id  = await this.db.documents.add({
157	      residentId,
158	      fileName:        DOMPurify.sanitize(file.name.trim()),
159	      mimeType:        file.type,
160	      sizeBytes:       file.size,
161	      fileHash,
162	      fileData,
163	      status:          'pending_review',
164	      consentRecordId,
165	      hidden:          false,
166	      createdAt:       now,
167	    });
168	
169	    const doc = await this.db.documents.get(id);
170	    this.audit.log(
171	      AuditAction.DOCUMENT_UPLOADED,
172	      actorId, actorRole,
173	      'document', id,
174	      undefined,
175	      {
176	        id, residentId,
177	        fileName: doc!.fileName,
178	        mimeType: doc!.mimeType,
179	        sizeBytes: doc!.sizeBytes,
180	        status: 'pending_review',
181	        fileHash: '[ENCRYPTED]',
182	      },
183	    );
184	
185	    // Index for full-text search
186	    this.searchService.reindexEntity({
187	      entityType: 'document',
188	      entityId: id,
189	      title: doc!.fileName,
190	      body: `pending_review`,
191	      tags: ['document', 'pending_review'],
192	      metadata: { mimeType: doc!.mimeType, sizeBytes: doc!.sizeBytes },
193	      category: 'document',
194	      createdAt: now,
195	    }).catch(() => {/* best-effort */});
196	
197	    return doc!;
198	  }
199	
200	  // --------------------------------------------------
201	  // reviewDocument — approve or reject with notes
202	  // --------------------------------------------------
203	
204	  async reviewDocument(
205	    id:          number,
206	    decision:    'approved' | 'rejected',
207	    reviewNotes: string,
208	    actorId:     number,
209	    actorRole:   string,
210	  ): Promise<HpDocument> {
211	    this.requireRole('compliance', 'admin');
212	    const before = await this.db.documents.get(id);
213	    if (!before) throw new Error('DOCUMENT_NOT_FOUND');
214	
215	    const sanitizedNotes = DOMPurify.sanitize(reviewNotes.trim());
216	    await this.db.documents.update(id, {
217	      status:      decision,
218	      reviewNotes: sanitizedNotes,
219	      reviewedBy:  actorId,
220	      reviewedAt:  new Date(),
221	    });
222	
223	    const after  = await this.db.documents.get(id);
224	    const action = decision === 'approved'
225	      ? AuditAction.DOCUMENT_APPROVED
226	      : AuditAction.DOCUMENT_REJECTED;
227	
228	    this.audit.log(action, actorId, actorRole, 'document', id,
229	      { ...before, fileHash: '[ENCRYPTED]', fileData: '[ENCRYPTED]' },
230	      { ...after,  fileHash: '[ENCRYPTED]', fileData: '[ENCRYPTED]' },
231	    );
232	
233	    return after!;
234	  }
235	
236	  // --------------------------------------------------
237	  // grantConsent — writes consent record, sets resident
238	  // --------------------------------------------------
239	
240	  async grantConsent(
241	    residentId: number,
242	    actorId:    number,
243	    actorRole:  string,
244	  ): Promise<number> {
245	    this.requireRole('resident', 'admin');
246	    const consentId = await this.db.consentRecords.add({
247	      residentId,
248	      action:        'granted',
249	      timestamp:     new Date(),
250	      policyVersion: this.POLICY_VERSION,
251	    });
252	    await this.db.residents.update(residentId, {
253	      consentGiven:     true,
254	      consentTimestamp: new Date(),
255	    });
256	    this.audit.log(AuditAction.CONSENT_GRANTED, actorId, actorRole, 'resident', residentId);
257	    return consentId;
258	  }
259	
260	  // --------------------------------------------------
261	  // revokeConsent — hides docs, writes consent record
262	  // --------------------------------------------------
263	
264	  async revokeConsent(
265	    residentId: number,
266	    actorId:    number,
267	    actorRole:  string,
268	  ): Promise<void> {
269	    this.requireRole('resident', 'admin');
270	    const docs = await this.db.documents
271	      .where('residentId').equals(residentId)
272	      .toArray();
273	
274	    for (const doc of docs) {
275	      if (!doc.hidden) {
276	        await this.db.documents.update(doc.id!, { hidden: true });
277	        this.audit.log(
278	          AuditAction.DOCUMENT_HIDDEN,
279	          actorId, actorRole,
280	          'document', doc.id!,
281	          { ...doc, fileHash: '[ENCRYPTED]', fileData: '[ENCRYPTED]' },
282	          { ...doc, hidden: true, fileHash: '[ENCRYPTED]', fileData: '[ENCRYPTED]' },
283	        );
284	      }
285	    }
286	
287	    await this.db.consentRecords.add({
288	      residentId,
289	      action:        'revoked',
290	      timestamp:     new Date(),
291	      policyVersion: this.POLICY_VERSION,
292	    });
293	    await this.db.residents.update(residentId, {
294	      consentGiven: false,
295	      consentTimestamp: undefined,
296	    });
297	    this.audit.log(AuditAction.CONSENT_REVOKED, actorId, actorRole, 'resident', residentId);
298	  }
299	
300	  // --------------------------------------------------
301	  // getConsentStatus — returns latest consent record
302	  // --------------------------------------------------
303	
304	  async getConsentStatus(residentId: number): Promise<ConsentStatus> {
305	    const records = await this.db.consentRecords
306	      .where('residentId').equals(residentId)
307	      .sortBy('timestamp');
308	
309	    if (records.length === 0) return { granted: false, record: undefined };
310	    const latest = records[records.length - 1];
311	    return { granted: latest.action === 'granted', record: latest };
312	  }
313	
314	  // --------------------------------------------------
315	  // getFileData — decrypt stored fileData for preview
316	  // Returns the raw base64 string of the original file.
317	  // --------------------------------------------------
318	
319	  async getFileData(doc: HpDocument): Promise<string> {
320	    if (!doc.fileData) return '';
321	    const dotIdx = doc.fileData.indexOf('.');
322	    if (dotIdx < 0) {
323	      // Legacy: plain base64 (older records before encryption)
324	      return doc.fileData;
325	    }
326	    const ciphertext = doc.fileData.slice(0, dotIdx);
327	    const iv         = doc.fileData.slice(dotIdx + 1);
328	    const key = this.getKey();
329	    return this.crypto.decryptRaw(ciphertext, iv, key);
330	  }
331	
332	  // --------------------------------------------------
333	  // createPreviewUrl — decrypts and creates a Blob URL
334	  // Caller must revoke with URL.revokeObjectURL() when done.
335	  // --------------------------------------------------
336	
337	  async createPreviewUrl(doc: HpDocument): Promise<string> {
338	    const base64 = await this.getFileData(doc);
339	    if (!base64) return '';
340	
341	    const binaryStr = atob(base64);
342	    const bytes = new Uint8Array(binaryStr.length);
343	    for (let i = 0; i < binaryStr.length; i++) {
344	      bytes[i] = binaryStr.charCodeAt(i);
345	    }
346	    const blob = new Blob([bytes], { type: doc.mimeType });
347	    return URL.createObjectURL(blob);
348	  }
349	
350	  // --------------------------------------------------
351	  // Helpers
352	  // --------------------------------------------------
353	
354	  formatSize(bytes: number): string {
355	    if (bytes < 1024)        return `${bytes} B`;
356	    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
357	    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
358	  }
359	}
