597	export class MyProfileComponent implements OnInit {
598	
599	  loading        = true;
600	  resident:      Resident | null = null;
601	  occupancyCtx:  ProfileOccupancy | null = null;
602	  consentChanging = false;
603	
604	  private readonly AVATAR_COLORS = [
605	    '#1e3a5f', '#0d9488', '#7c3aed', '#db2777',
606	    '#ea580c', '#16a34a', '#2563eb', '#b45309',
607	  ];
608	
609	  constructor(
610	    private residentService: ResidentService,
611	    private propertyService: PropertyService,
612	    private docService:      DocumentService,
613	    private db:  DbService,
614	    private toast: ToastService,
615	    private cdr: ChangeDetectorRef,
616	  ) {}
617	
618	  ngOnInit(): void {
619	    this.loadProfile();
620	  }
621	
622	  async toggleConsent(): Promise<void> {
623	    if (!this.resident?.id) return;
624	    this.consentChanging = true;
625	    this.cdr.markForCheck();
626	    try {
627	      if (this.resident.consentGiven) {
628	        await this.docService.revokeConsent(this.resident.id, 0, 'resident');
629	        this.toast.show('Consent revoked. Your documents are now hidden from staff.', 'info');
630	      } else {
631	        await this.docService.grantConsent(this.resident.id, 0, 'resident');
632	        this.toast.show('Consent granted. You can now upload documents.', 'success');
633	      }
634	      // Refresh resident record
635	      const updated = await this.residentService.getResident(this.resident.id);
636	      if (updated) this.resident = updated;
637	    } catch {
638	      this.toast.show('Failed to update consent. Please try again.', 'error');
639	    } finally {
640	      this.consentChanging = false;
641	      this.cdr.markForCheck();
642	    }
643	  }
644	
645	  private async loadProfile(): Promise<void> {
646	    this.loading = true;
647	    this.cdr.markForCheck();
648	    try {
649	      // Retrieve the resident profile bound to the authenticated session user
650	      const profile = await this.residentService.getMyProfile();
651	      this.resident = profile ?? null;
652	
653	      if (this.resident?.id != null) {
654	        const activeOcc = await this.propertyService.getActiveOccupancy(this.resident.id);
655	        if (activeOcc) {
656	          const room = await this.db.rooms.get(activeOcc.roomId);
657	          if (room) {
658	            const unit = await this.db.units.get(room.unitId);
659	            if (unit) {
660	              const building = await this.db.buildings.get(unit.buildingId);
661	              if (building) {
662	                this.occupancyCtx = { occupancy: activeOcc, room, unit, building };
663	              }
664	            }
665	          }
666	        }
667	      }
668	    } finally {
669	      this.loading = false;
670	      this.cdr.markForCheck();
671	    }
672	  }
673	
674	  get initials(): string {
675	    if (!this.resident) return '?';
676	    return `${this.resident.firstName[0] ?? ''}${this.resident.lastName[0] ?? ''}`.toUpperCase();
677	  }
678	
679	  get avatarBg(): string {
680	    if (!this.resident) return '#1e3a5f';
681	    const name = `${this.resident.firstName}${this.resident.lastName}`;
682	    let hash = 0;
683	    for (let i = 0; i < name.length; i++) {
684	      hash = (hash * 31 + name.charCodeAt(i)) & 0xffffffff;
685	    }
686	    return this.AVATAR_COLORS[Math.abs(hash) % this.AVATAR_COLORS.length];
687	  }
