375	export class AuditLogComponent implements OnInit {
376	
377	  allLogs:      AuditLog[] = [];
378	  filteredLogs: AuditLog[] = [];
379	  pagedLogs:    AuditLog[] = [];
380	  loading       = true;
381	
382	  // Filters
383	  filterActorSearch = '';
384	  filterRole        = '';
385	  filterAction      = '';
386	  filterDateFrom    = '';
387	  filterDateTo      = '';
388	  filterAnomalyOnly = false;
389	
390	  actionOptions: string[] = Object.values(AuditAction);
391	
392	  // Pagination
393	  pageSize    = 25;
394	  currentPage = 0;
395	
396	  get pageEnd(): number {
397	    return Math.min((this.currentPage + 1) * this.pageSize, this.filteredLogs.length);
398	  }
399	
400	  // Detail drawer
401	  drawerOpen  = false;
402	  selectedLog: AuditLog | null = null;
403	
404	  // Export modal
405	  exportModalOpen = false;
406	
407	  constructor(
408	    private auditService: AuditService,
409	    private cdr:          ChangeDetectorRef,
410	  ) {}
411	
412	  ngOnInit(): void {
413	    this.loadLogs();
414	  }
415	
416	  // --------------------------------------------------
417	  // Load
418	  // --------------------------------------------------
419	
420	  private async loadLogs(): Promise<void> {
421	    this.loading = true;
422	    this.cdr.markForCheck();
423	
424	    this.allLogs = await this.auditService.getLogs();
425	    this.applyFilters();
426	
427	    this.loading = false;
428	    this.cdr.markForCheck();
429	  }
430	
431	  // --------------------------------------------------
432	  // Filters
433	  // --------------------------------------------------
434	
435	  applyFilters(): void {
436	    let logs = [...this.allLogs];
437	
438	    if (this.filterActorSearch.trim()) {
439	      const search = this.filterActorSearch.trim().toLowerCase();
440	      logs = logs.filter(l => String(l.actorId).includes(search));
441	    }
442	    if (this.filterRole) {
443	      logs = logs.filter(l => l.actorRole === this.filterRole);
444	    }
445	    if (this.filterAction) {
446	      logs = logs.filter(l => l.action === this.filterAction);
447	    }
448	    if (this.filterDateFrom) {
449	      const from = new Date(this.filterDateFrom);
450	      logs = logs.filter(l => l.timestamp >= from);
451	    }
452	    if (this.filterDateTo) {
453	      const to = new Date(this.filterDateTo);
454	      to.setHours(23, 59, 59, 999);
455	      logs = logs.filter(l => l.timestamp <= to);
456	    }
457	    if (this.filterAnomalyOnly) {
458	      logs = logs.filter(l => l.anomalyFlagged);
459	    }
460	
461	    this.filteredLogs = logs;
462	    this.currentPage  = 0;
463	    this.paginate();
464	    this.cdr.markForCheck();
465	  }
466	
467	  paginate(): void {
468	    const start = this.currentPage * this.pageSize;
469	    this.pagedLogs = this.filteredLogs.slice(start, start + this.pageSize);
470	    this.cdr.markForCheck();
471	  }
472	
473	  // --------------------------------------------------
474	  // Detail drawer
475	  // --------------------------------------------------
476	
477	  openDetail(log: AuditLog): void {
478	    this.selectedLog = log;
479	    this.drawerOpen  = true;
480	    this.cdr.markForCheck();
481	  }
482	
483	  formatJson(value: unknown): string {
484	    try { return JSON.stringify(value, null, 2); }
485	    catch { return String(value); }
486	  }
487	
488	  asRole(role: string): UserRole | null {
489	    const valid: UserRole[] = ['admin', 'resident', 'compliance', 'analyst'];
490	    return valid.includes(role as UserRole) ? role as UserRole : null;
491	  }
492	
493	  // --------------------------------------------------
494	  // Export
495	  // --------------------------------------------------
496	
497	  doExport(): void {
498	    const data = JSON.stringify(this.filteredLogs, null, 2);
499	    const blob = new Blob([data], { type: 'application/json' });
500	    const url  = URL.createObjectURL(blob);
501	    const a    = document.createElement('a');
502	    a.href     = url;
503	    a.download = `harborpoint-audit-${Date.now()}.json`;
504	    a.click();
505	    URL.revokeObjectURL(url);
506	    this.exportModalOpen = false;
507	    this.cdr.markForCheck();
508	  }
509	}
