8	
9	export type EnrollmentResult =
10	  | { success: true; status: 'enrolled' | 'waitlisted'; enrollment: Enrollment }
11	  | { success: false; reason: string };
12	
13	export interface CreateCourseParams {
14	  title:         string;
15	  description:   string;
16	  category:      string;
17	  prerequisites: CoursePrerequisite[];
18	}
19	
20	export interface CreateRoundParams {
21	  courseId:         number;
22	  startAt:          Date;
23	  endAt:            Date;
24	  capacity:         number;
25	  waitlistCapacity: number;
