30	@Injectable({ providedIn: 'root' })
31	export class EnrollmentService {
32	
33	  constructor(
34	    private db:          DbService,
35	    private audit:       AuditService,
36	    private authService: AuthService,
37	    private anomaly:     AnomalyService,
38	    private searchService: SearchService,
39	  ) {}
40	
41	  private requireRole(...allowedRoles: string[]): void {
42	    const current = this.authService.getCurrentRole();
43	    if (!current || !allowedRoles.includes(current)) {
44	      throw new Error(`Unauthorized: requires role ${allowedRoles.join(' or ')}`);
45	    }
46	  }
47	
48	  // --------------------------------------------------
49	  // Course Management
50	  // --------------------------------------------------
51	
52	  async getCourses(): Promise<Course[]> {
53	    return this.db.courses.toArray();
54	  }
55	
56	  async getCourse(id: number): Promise<Course | undefined> {
57	    return this.db.courses.get(id);
58	  }
59	
60	  async createCourse(params: CreateCourseParams): Promise<Course> {
61	    this.requireRole('admin');
62	    const now = new Date();
63	    const id  = await this.db.courses.add({
64	      title:         DOMPurify.sanitize(params.title),
65	      description:   DOMPurify.sanitize(params.description),
66	      category:      DOMPurify.sanitize(params.category),
67	      prerequisites: params.prerequisites,
68	      createdAt:     now,
69	      updatedAt:     now,
70	    });
71	    const course = (await this.db.courses.get(id))!;
72	
73	    // Index for full-text search
74	    this.searchService.reindexEntity({
75	      entityType: 'course',
76	      entityId: id,
77	      title: course.title,
78	      body: course.description,
79	      tags: ['course', course.category],
80	      metadata: {},
81	      category: 'course',
82	      createdAt: now,
83	    }).catch(() => {/* best-effort */});
84	
85	    return course;
86	  }
87	
88	  // --------------------------------------------------
89	  // Round Management
90	  // --------------------------------------------------
91	
92	  async getCourseRounds(courseId: number): Promise<CourseRound[]> {
93	    return this.db.courseRounds.where('courseId').equals(courseId).toArray();
94	  }
95	
96	  async createRound(params: CreateRoundParams): Promise<CourseRound> {
97	    this.requireRole('admin');
98	    const id = await this.db.courseRounds.add({
99	      courseId:         params.courseId,
100	      startAt:          params.startAt,
101	      endAt:            params.endAt,
102	      capacity:         params.capacity,
103	      waitlistCapacity: params.waitlistCapacity,
104	      addCutoffAt:      params.addCutoffAt,
105	      dropCutoffAt:     new Date(params.startAt.getTime() - 2 * 60 * 60 * 1000),
106	      enrolled:         [],
107	      waitlisted:       [],
108	      status:           'open',
109	    });
110	    return (await this.db.courseRounds.get(id))!;
111	  }
112	
113	  // --------------------------------------------------
114	  // Enroll or Waitlist
115	  // --------------------------------------------------
116	
117	  async enroll(residentId: number, roundId: number, actorRole: string): Promise<EnrollmentResult> {
118	    this.requireRole('resident', 'admin');
119	    const round = await this.db.courseRounds.get(roundId);
120	    if (!round) return { success: false, reason: 'ROUND_NOT_FOUND' };
121	    if (round.status !== 'open') return { success: false, reason: 'ROUND_NOT_OPEN' };
122	
123	    const now = new Date();
124	    if (now > round.addCutoffAt) return { success: false, reason: 'ADD_CUTOFF_PASSED' };
125	
126	    // Check duplicate enrollment before anomaly tracking — a re-submission by an
127	    // already-enrolled resident is not a security anomaly, just a duplicate request.
128	    const existing = await this.db.enrollments
129	      .filter(e => e.residentId === residentId && e.roundId === roundId && e.status !== 'dropped')
130	      .first();
131	    if (existing) return { success: false, reason: 'ALREADY_ENROLLED' };
132	
133	    const anomalyKey = `${residentId}-${roundId}`;
134	    const isAnomaly  = this.anomaly.trackRegistrationAttempt(anomalyKey);
135	    if (isAnomaly) {
136	      return { success: false, reason: 'ANOMALY_DETECTED' };
137	    }
138	
139	    // Check prerequisites
140	    const prereqResult = await this.checkPrerequisites(residentId, round.courseId);
141	    if (!prereqResult.ok) return { success: false, reason: prereqResult.reason! };
142	
143	    const historyEntry: EnrollmentHistory = {
144	      status:    'enrolled',
145	      changedAt: now,
146	      changedBy: residentId,
147	    };
148	
149	    if (round.enrolled.length < round.capacity) {
150	      // Enroll directly
151	      await this.db.courseRounds.update(roundId, {
152	        enrolled: [...round.enrolled, residentId],
153	      });
154	
155	      const id = await this.db.enrollments.add({
156	        residentId,
157	        courseId:        round.courseId,
158	        roundId,
159	        status:          'enrolled',
160	        enrolledAt:      now,
161	        historySnapshot: [historyEntry],
162	      });
163	
164	      const enrollment = await this.db.enrollments.get(id);
165	
166	      this.audit.log(AuditAction.ENROLLMENT_CREATED, residentId, actorRole, 'enrollment', id);
167	
168	      return { success: true, status: 'enrolled', enrollment: enrollment! };
169	    }
170	
171	    if (round.waitlisted.length < round.waitlistCapacity) {
172	      // Add to waitlist
173	      const wlEntry: EnrollmentHistory = { ...historyEntry, status: 'waitlisted' };
174	      await this.db.courseRounds.update(roundId, {
175	        waitlisted: [...round.waitlisted, residentId],
176	      });
177	
178	      const id = await this.db.enrollments.add({
179	        residentId,
180	        courseId:        round.courseId,
181	        roundId,
182	        status:          'waitlisted',
183	        enrolledAt:      now,
184	        historySnapshot: [wlEntry],
185	      });
186	
187	      const enrollment = await this.db.enrollments.get(id);
188	
189	      this.audit.log(AuditAction.WAITLIST_ADDED, residentId, actorRole, 'enrollment', id);
190	
191	      return { success: true, status: 'waitlisted', enrollment: enrollment! };
192	    }
193	
194	    return { success: false, reason: 'CAPACITY_EXCEEDED' };
195	  }
196	
197	  // --------------------------------------------------
198	  // Drop Enrollment
199	  // --------------------------------------------------
200	
201	  async drop(enrollmentId: number, actorId: number, actorRole: string, reasonCode: string): Promise<{ success: boolean; reason?: string }> {
202	    this.requireRole('resident', 'admin');
203	    const enrollment = await this.db.enrollments.get(enrollmentId);
204	    if (!enrollment) return { success: false, reason: 'NOT_FOUND' };
205	    if (enrollment.status === 'dropped') return { success: false, reason: 'ALREADY_DROPPED' };
206	
207	    const round = await this.db.courseRounds.get(enrollment.roundId);
208	    if (!round) return { success: false, reason: 'ROUND_NOT_FOUND' };
209	
210	    const now = new Date();
211	    const twoHoursBeforeStart = new Date(round.startAt.getTime() - 2 * 60 * 60 * 1000);
212	    if (now >= twoHoursBeforeStart) {
213	      return { success: false, reason: 'DROP_CUTOFF_PASSED' };
214	    }
215	
216	    const historyEntry: EnrollmentHistory = {
217	      status:    'dropped',
218	      changedAt: now,
219	      changedBy: actorId,
220	      reason:    reasonCode,
221	    };
222	
223	    await this.db.enrollments.update(enrollmentId, {
224	      status:          'dropped',
225	      droppedAt:       now,
226	      dropReasonCode:  reasonCode,
227	      historySnapshot: [...enrollment.historySnapshot, historyEntry],
228	    });
229	
230	    // Remove from enrolled / waitlisted list
231	    if (enrollment.status === 'enrolled') {
232	      await this.db.courseRounds.update(enrollment.roundId, {
233	        enrolled: round.enrolled.filter(id => id !== enrollment.residentId),
234	      });
235	      await this.backfillFromWaitlist(enrollment.roundId, actorRole);
236	    } else {
237	      await this.db.courseRounds.update(enrollment.roundId, {
238	        waitlisted: round.waitlisted.filter(id => id !== enrollment.residentId),
239	      });
240	    }
241	
242	    this.audit.log(AuditAction.ENROLLMENT_DROPPED, actorId, actorRole, 'enrollment', enrollmentId);
243	
244	    return { success: true };
245	  }
246	
247	  // --------------------------------------------------
248	  // Waitlist Backfill — FIFO / deterministic
249	  // --------------------------------------------------
250	
251	  private async backfillFromWaitlist(roundId: number, actorRole: string): Promise<void> {
252	    const round = await this.db.courseRounds.get(roundId);
253	    if (!round || round.waitlisted.length === 0) return;
254	    if (round.enrolled.length >= round.capacity) return;
255	
256	    const nextResidentId = round.waitlisted[0];
257	
258	    // Promote from waitlist
259	    await this.db.courseRounds.update(roundId, {
260	      enrolled:   [...round.enrolled, nextResidentId],
261	      waitlisted: round.waitlisted.slice(1),
262	    });
263	
264	    // Update enrollment record
265	    const enrollment = await this.db.enrollments
266	      .filter(e => e.residentId === nextResidentId && e.roundId === roundId && e.status === 'waitlisted')
267	      .first();
268	
269	    if (enrollment?.id) {
270	      const historyEntry: EnrollmentHistory = {
271	        status:    'enrolled',
272	        changedAt: new Date(),
273	        changedBy: 0, // system-triggered
274	        reason:    'WAITLIST_PROMOTION',
275	      };
276	      await this.db.enrollments.update(enrollment.id, {
277	        status:          'enrolled',
278	        historySnapshot: [...enrollment.historySnapshot, historyEntry],
279	      });
280	      this.audit.log(AuditAction.WAITLIST_PROMOTED, nextResidentId, actorRole, 'enrollment', enrollment.id);
281	    }
282	  }
283	
284	  // --------------------------------------------------
285	  // Prerequisites Check (public for UI eligibility display)
286	  // --------------------------------------------------
287	
288	  async checkPrerequisites(residentId: number, courseId: number): Promise<{ ok: boolean; reason?: string; details?: { prereq: CoursePrerequisite; met: boolean; reason?: string }[] }> {
289	    const course = await this.db.courses.get(courseId);
290	    if (!course) return { ok: false, reason: 'COURSE_NOT_FOUND' };
291	
292	    const resident = await this.db.residents.get(residentId);
293	    if (!resident) return { ok: false, reason: 'RESIDENT_NOT_FOUND' };
294	
295	    const details: { prereq: CoursePrerequisite; met: boolean; reason?: string }[] = [];
296	
297	    for (const prereq of course.prerequisites) {
298	      if (prereq.type === 'active_resident') {
299	        const met = resident.status === 'active';
300	        details.push({ prereq, met, reason: met ? undefined : 'PREREQ_NOT_ACTIVE_RESIDENT' });
301	        if (!met) return { ok: false, reason: 'PREREQ_NOT_ACTIVE_RESIDENT', details };
302	      }
303	      if (prereq.type === 'age') {
304	        const age = this.calculateAge(resident.dateOfBirth);
305	        const met = age >= (prereq.value as number);
306	        details.push({ prereq, met, reason: met ? undefined : `PREREQ_AGE_${prereq.value}` });
307	        if (!met) return { ok: false, reason: `PREREQ_AGE_${prereq.value}`, details };
308	      }
309	      if (prereq.type === 'prior_completion') {
310	        const completed = await this.db.enrollments
311	          .filter(e => e.residentId === residentId && e.courseId === (prereq.value as number) && e.status === 'completed')
312	          .count();
313	        const met = completed > 0;
314	        details.push({ prereq, met, reason: met ? undefined : 'PREREQ_PRIOR_COMPLETION' });
315	        if (!met) return { ok: false, reason: 'PREREQ_PRIOR_COMPLETION', details };
316	      }
317	    }
318	
319	    return { ok: true, details };
320	  }
321	
322	  private calculateAge(dob: Date): number {
323	    const now = new Date();
324	    let age   = now.getFullYear() - dob.getFullYear();
325	    const m   = now.getMonth() - dob.getMonth();
326	    if (m < 0 || (m === 0 && now.getDate() < dob.getDate())) age--;
327	    return age;
328	  }
329	
330	  // --------------------------------------------------
331	  // Query helpers
332	  // --------------------------------------------------
333	
334	  async getEnrollmentsForResident(residentId: number): Promise<Enrollment[]> {
335	    return this.db.enrollments.where('residentId').equals(residentId).toArray();
336	  }
337	
338	  async getRoundEnrollments(roundId: number): Promise<Enrollment[]> {
339	    return this.db.enrollments.where('roundId').equals(roundId).toArray();
340	  }
341	
342	  /**
343	   * Returns the historySnapshot for a given enrollment in chronological order.
344	   */
345	  async getEnrollmentHistory(enrollmentId: number): Promise<EnrollmentHistory[]> {
346	    const enrollment = await this.db.enrollments.get(enrollmentId);
347	    return enrollment?.historySnapshot ?? [];
348	  }
