652	    this.loadFacets();
653	    this.loadTrending();
654	
655	    // Debounced search-as-you-type
656	    this.subs.push(
657	      this.query$.pipe(debounceTime(350), distinctUntilChanged()).subscribe(q => {
658	        if (q.trim().length >= 2) this.doSearch();
659	      }),
