671	  async doSearch(): Promise<void> {
672	    const q = this.query.trim();
673	    if (!q) return;
674	
675	    this.lastQuery  = q;
676	    this.isLoading  = true;
677	    this.hasSearched = true;
678	    this.spellSuggestion = null;
679	    this.cdr.markForCheck();
680	
681	    try {
682	      const filters = this.buildFilters();
683	      this.results  = await this.searchSvc.search(q, undefined, filters);
684	      this.filteredResults = this.results;
685	
686	      // Check spell suggestion if no results
687	      if (this.results.length === 0) {
688	        this.spellSuggestion = await this.searchSvc.getSpellSuggestion(q);
689	      }
690	
