54	    password: string,
55	    actorId: number,
56	    actorRole: string,
57	    overwrite = false,
58	  ): Promise<{ success: boolean; reason?: string }> {
59	    this.requireRole('admin');
60	    try {
61	      const text = await file.text();
62	      const payload = JSON.parse(text);
63	
64	      // Validate payload shape
65	      if (!payload.ciphertext || !payload.iv || !payload.salt) {
66	        return { success: false, reason: 'INVALID_FILE_FORMAT' };
67	      }
68	
69	      let json: string;
70	      try {
71	        json = await this.crypto.decrypt(payload, password);
72	      } catch {
73	        return { success: false, reason: 'WRONG_PASSWORD' };
74	      }
75	
76	      let data: Record<string, unknown[]>;
77	      try {
78	        data = JSON.parse(json);
79	      } catch {
80	        return { success: false, reason: 'CORRUPT_DATA' };
81	      }
82	
83	      // Schema validation: ensure expected keys exist
84	      const requiredKeys = ['buildings', 'units', 'rooms', 'residents'];
85	      for (const key of requiredKeys) {
86	        if (!Array.isArray(data[key])) {
87	          return { success: false, reason: `MISSING_KEY_${key.toUpperCase()}` };
88	        }
89	      }
90	
91	      // Prototype pollution guard
92	      const sanitized = this.sanitizeImport(data);
93	
94	      await this.db.importAll(sanitized, overwrite);
95	
96	      // Rebuild search index after import
97	      try { await this.search.buildIndex(); } catch { /* non-critical */ }
98	
99	      this.audit.log(AuditAction.DATA_IMPORTED, actorId, actorRole, 'database', 'all');
100	
101	      return { success: true };
102	    } catch (err) {
103	      this.logger.error('ImportExportService', 'Import failed', err);
104	      return { success: false, reason: 'UNKNOWN_ERROR' };
105	    }
106	  }
107	
108	  // --------------------------------------------------
109	  // Prototype Pollution Guard
110	  // --------------------------------------------------
111	
112	  private sanitizeImport(data: Record<string, unknown>): Record<string, unknown[]> {
113	    const result: Record<string, unknown[]> = {};
114	    for (const [key, value] of Object.entries(data)) {
115	      // Reject dangerous keys
116	      if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;
117	      if (!Array.isArray(value)) continue;
118	
119	      result[key] = value.map(item => {
120	        if (typeof item !== 'object' || item === null) return item;
121	        const clean: Record<string, unknown> = {};
122	        for (const [k, v] of Object.entries(item as Record<string, unknown>)) {
123	          if (k === '__proto__' || k === 'constructor' || k === 'prototype') continue;
124	          clean[k] = v;
125	        }
126	        return clean;
127	      });
128	    }
129	    return result;
130	  }
