28	  DATA_IMPORTED          = 'DATA_IMPORTED',
29	  ANOMALY_FLAGGED        = 'ANOMALY_FLAGGED',
30	  SESSION_LOCKED         = 'SESSION_LOCKED',
31	  SESSION_REAUTH         = 'SESSION_REAUTH',
32	  DOCUMENT_HIDDEN        = 'DOCUMENT_HIDDEN',
