37	// =====================================================
38	// AuditService — APPEND-ONLY
39	// The auditLogs table must NEVER have update or delete calls.
40	// Fire-and-forget at call sites (no await required).
41	// =====================================================
42	
43	@Injectable({ providedIn: 'root' })
44	export class AuditService {
45	
46	  constructor(private db: DbService, private logger: LoggerService) {}
47	
48	  /**
49	   * Write an immutable audit entry.
50	   * Fire-and-forget — no await required at call sites.
51	   * All errors are swallowed to prevent audit failures from
52	   * disrupting user-facing operations.
53	   */
54	  log(
55	    action: AuditAction | string,
56	    actorId: number,
57	    actorRole: string,
58	    targetType: string,
59	    targetId: number | string,
60	    before?: unknown,
61	    after?: unknown,
62	    anomalyFlagged = false,
63	  ): void {
64	    // Intentionally NOT awaited — fire-and-forget
65	    this.db.auditLogs.add({
66	      timestamp: new Date(),
67	      actorId,
68	      actorRole,
69	      action,
70	      targetType,
71	      targetId,
72	      before,
73	      after,
74	      anomalyFlagged,
75	    }).catch(err => {
76	      // Silently log to console — never throw from audit
77	      this.logger.error('AuditService', 'Failed to write audit entry', err);
78	    });
79	  }
80	
81	  /**
82	   * Query audit logs — used by the Audit Log viewer.
83	   * Returns all entries sorted descending by timestamp.
84	   */
85	  async getLogs(options?: {
86	    limit?: number;
87	    actorId?: number;
88	    action?: string;
89	    anomalyOnly?: boolean;
90	    from?: Date;
91	    to?: Date;
92	  }): Promise<import('./db.service').AuditLog[]> {
93	    let query = this.db.auditLogs.orderBy('timestamp').reverse();
94	
95	    const results = await query.toArray();
96	
97	    return results.filter(entry => {
98	      if (options?.actorId !== undefined && entry.actorId !== options.actorId) return false;
99	      if (options?.action     && entry.action !== options.action) return false;
100	      if (options?.anomalyOnly && !entry.anomalyFlagged) return false;
101	      if (options?.from       && entry.timestamp < options.from) return false;
102	      if (options?.to         && entry.timestamp > options.to) return false;
103	      return true;
104	    }).slice(0, options?.limit ?? 10_000);
105	  }
106	}
