201	  async drop(enrollmentId: number, actorId: number, actorRole: string, reasonCode: string): Promise<{ success: boolean; reason?: string }> {
202	    this.requireRole('resident', 'admin');
203	    const enrollment = await this.db.enrollments.get(enrollmentId);
204	    if (!enrollment) return { success: false, reason: 'NOT_FOUND' };
205	    if (enrollment.status === 'dropped') return { success: false, reason: 'ALREADY_DROPPED' };
206	
207	    const round = await this.db.courseRounds.get(enrollment.roundId);
208	    if (!round) return { success: false, reason: 'ROUND_NOT_FOUND' };
209	
210	    const now = new Date();
211	    const twoHoursBeforeStart = new Date(round.startAt.getTime() - 2 * 60 * 60 * 1000);
212	    if (now >= twoHoursBeforeStart) {
213	      return { success: false, reason: 'DROP_CUTOFF_PASSED' };
214	    }
215	
216	    const historyEntry: EnrollmentHistory = {
217	      status:    'dropped',
218	      changedAt: now,
219	      changedBy: actorId,
220	      reason:    reasonCode,
221	    };
222	
223	    await this.db.enrollments.update(enrollmentId, {
224	      status:          'dropped',
225	      droppedAt:       now,
226	      dropReasonCode:  reasonCode,
227	      historySnapshot: [...enrollment.historySnapshot, historyEntry],
228	    });
229	
230	    // Remove from enrolled / waitlisted list
231	    if (enrollment.status === 'enrolled') {
232	      await this.db.courseRounds.update(enrollment.roundId, {
233	        enrolled: round.enrolled.filter(id => id !== enrollment.residentId),
234	      });
235	      await this.backfillFromWaitlist(enrollment.roundId, actorRole);
236	    } else {
237	      await this.db.courseRounds.update(enrollment.roundId, {
238	        waitlisted: round.waitlisted.filter(id => id !== enrollment.residentId),
239	      });
240	    }
241	
242	    this.audit.log(AuditAction.ENROLLMENT_DROPPED, actorId, actorRole, 'enrollment', enrollmentId);
243	
244	    return { success: true };
245	  }
