630	  // --------------------------------------------------
631	  // Computed
632	  // --------------------------------------------------
633	
634	  get atLimit(): boolean {
635	    return this.documents.length >= this.docService.MAX_FILES_PER_RESIDENT;
636	  }
637	
638	  statusClass(doc: HpDocument): string {
639	    if (doc.hidden) return 'doc-card__badge--pending';
640	    switch (doc.status) {
641	      case 'pending_review': return 'doc-card__badge--pending';
642	      case 'approved':       return 'doc-card__badge--approved';
643	      case 'rejected':       return 'doc-card__badge--rejected';
644	      default:               return 'doc-card__badge--pending';
645	    }
646	  }
