648	  fileIconBg(mimeType: string): string {
649	    if (mimeType === 'application/pdf') return '#ef4444';
650	    if (mimeType === 'image/jpeg')      return '#3b82f6';
651	    if (mimeType === 'image/png')       return '#10b981';
652	    return '#6b7280';
