659	  onFileSelected(event: Event): void {
660	    const input = event.target as HTMLInputElement;
661	    const file  = input.files?.[0];
662	    if (!file) return;
663	    this.validateAndStagePending(file);
664	    input.value = ''; // Reset so same file can be re-selected
665	  }
