667	  onDrop(event: DragEvent): void {
668	    event.preventDefault();
669	    this.dragOver = false;
670	    const file = event.dataTransfer?.files?.[0];
671	    if (file) this.validateAndStagePending(file);
672	  }
673	
674	  private validateAndStagePending(file: File): void {
675	    if (!this.docService.ALLOWED_MIME_TYPES.includes(file.type as never)) {
676	      this.toast.show('Only PDF, JPG, and PNG files are allowed.', 'error');
677	      return;
678	    }
679	    if (file.size > this.docService.MAX_FILE_SIZE_BYTES) {
680	      this.toast.show(`File exceeds the 10 MB limit (${this.docService.formatSize(file.size)}).`, 'error');
681	      return;
682	    }
683	    this.pendingFile = file;
684	    this.cdr.markForCheck();
685	  }
