687	  removePending(): void {
688	    this.pendingFile = null;
689	    this.uploadProgress = 0;
690	    this.cdr.markForCheck();
691	  }
692	
693	  // --------------------------------------------------
694	  // Upload flow (with consent gate)
695	  // --------------------------------------------------
696	
697	  startUpload(): void {
698	    if (!this.pendingFile) return;
699	    if (!this.consentGranted) {
700	      // Show consent modal — upload continues in onConsentConfirmed
701	      this.consentModalOpen = true;
702	      this.cdr.markForCheck();
703	      return;
704	    }
705	    this.executeUpload();
706	  }
