708	  async onConsentConfirmed(): Promise<void> {
709	    this.consentModalOpen = false;
710	    if (this.residentId == null) return;
711	    try {
712	      await this.docService.grantConsent(this.residentId, this.actorId, this.actorRole);
713	      this.consentGranted = true;
714	      this.consentStatusChanged.emit(true);
715	      this.cdr.markForCheck();
716	      this.executeUpload();
717	    } catch {
718	      this.toast.show('Failed to record consent. Please try again.', 'error');
719	    }
720	  }
721	
722	  private async executeUpload(): Promise<void> {
723	    if (!this.pendingFile || this.residentId == null) return;
724	
725	    this.uploading      = true;
726	    this.uploadProgress = 0;
727	    this.cdr.markForCheck();
728	
729	    // Simulated progress (1.5s animation) while real upload happens
730	    const progressInterval = setInterval(() => {
731	      this.uploadProgress = Math.min(this.uploadProgress + 8, 90);
732	      this.cdr.markForCheck();
733	    }, 120);
734	
735	    try {
736	      const consent = await this.docService.getConsentStatus(this.residentId);
737	      if (!consent.granted || !consent.record?.id) {
738	        throw new Error('CONSENT_REQUIRED');
739	      }
740	
741	      const doc = await this.docService.uploadDocument(
742	        this.residentId,
743	        this.pendingFile,
744	        consent.record.id,
745	        this.actorId,
746	        this.actorRole,
747	      );
748	
749	      clearInterval(progressInterval);
750	      this.uploadProgress = 100;
751	      this.cdr.markForCheck();
752	
753	      await new Promise(r => setTimeout(r, 300));
754	
755	      this.documents  = [doc, ...this.documents];
756	      this.pendingFile = null;
757	      this.uploadProgress = 0;
758	      this.documentUploaded.emit(doc);
759	      this.toast.show(`"${doc.fileName}" uploaded successfully.`, 'success');
760	    } catch (err: unknown) {
761	      clearInterval(progressInterval);
762	      this.uploadProgress = 0;
763	      const msg = err instanceof Error ? err.message : 'Upload failed';
764	      const friendlyMsg = msg === 'MAX_FILES_REACHED'
765	        ? 'You have reached the maximum of 5 documents.'
766	        : msg === 'INVALID_FILE_TYPE'
767	          ? 'Only PDF, JPG, and PNG files are allowed.'
768	          : msg === 'FILE_TOO_LARGE'
769	            ? 'File exceeds the 10 MB limit.'
770	            : 'Upload failed. Please try again.';
771	      this.toast.show(friendlyMsg, 'error');
772	    } finally {
773	      this.uploading = false;
774	      this.cdr.markForCheck();
775	    }
776	  }
777	
778	  // --------------------------------------------------
779	  // Refresh (called by parent after review)
780	  // --------------------------------------------------
781	
782	  async refresh(): Promise<void> {
783	    await this.loadDocuments();
784	  }
