568	
569	  rejectNotesCtrl = new FormControl('', [Validators.minLength(10)]);
570	
571	  private currentPreviewUrl = '';
572	
573	  private readonly AVATAR_COLORS = [
574	    '#1e3a5f', '#0d9488', '#7c3aed', '#db2777',
575	    '#ea580c', '#16a34a', '#2563eb', '#b45309',
576	  ];
