585	  // Lifecycle
586	  // --------------------------------------------------
587	
588	  ngOnChanges(changes: SimpleChanges): void {
589	    if (changes['document'] || changes['open']) {
590	      if (this.open && this.document) {
591	        this.resetState();
592	        this.loadPreview();
593	      } else if (!this.open) {
594	        this.revokePreview();
