598	
599	  private resetState(): void {
600	    this.rejectMode    = false;
601	    this.saving        = false;
602	    this.previewUrl    = null;
603	    this.previewError  = false;
604	    this.rejectNotesCtrl.reset('');
605	    this.confirmApproveModal = false;
606	    this.confirmRejectModal  = false;
607	  }
608	
609	  private async loadPreview(): Promise<void> {
610	    if (!this.document) return;
611	    this.previewError = false;
612	    this.cdr.markForCheck();
613	    try {
614	      const url = await this.docService.createPreviewUrl(this.document);
615	      this.revokePreview();
616	      this.currentPreviewUrl = url;
617	      this.previewUrl = url;
618	    } catch {
619	      this.previewError = true;
620	    } finally {
621	      this.cdr.markForCheck();
622	    }
623	  }
624	
625	  private revokePreview(): void {
626	    if (this.currentPreviewUrl) {
627	      URL.revokeObjectURL(this.currentPreviewUrl);
628	      this.currentPreviewUrl = '';
629	      this.previewUrl = null;
630	    }
631	  }
632	
633	  // --------------------------------------------------
634	  // Computed
635	  // --------------------------------------------------
636	
637	  get isImage(): boolean {
638	    return this.document?.mimeType.startsWith('image/') ?? false;
639	  }
640	
641	  avatarBg(first: string, last: string): string {
642	    const name = `${first}${last}`;
643	    let hash = 0;
644	    for (let i = 0; i < name.length; i++) {
645	      hash = (hash * 31 + name.charCodeAt(i)) & 0xffffffff;
646	    }
647	    return this.AVATAR_COLORS[Math.abs(hash) % this.AVATAR_COLORS.length];
648	  }
649	
650	  friendlyType(mime: string): string {
651	    switch (mime) {
652	      case 'application/pdf': return 'PDF';
653	      case 'image/jpeg':      return 'JPEG Image';
