672	  async executeApprove(): Promise<void> {
673	    if (!this.document?.id) return;
674	    this.saving = true;
675	    this.confirmApproveModal = false;
676	    this.cdr.markForCheck();
677	    try {
678	      const updated = await this.docService.reviewDocument(
