701	
702	  async executeReject(): Promise<void> {
703	    if (!this.document?.id) return;
704	    const notes = this.rejectNotesCtrl.value ?? '';
705	    if (notes.length < 10) return;
706	
707	    this.saving = true;
708	    this.confirmRejectModal = false;
