153	    private router: Router,
154	  ) {}
155	
156	  ngOnInit(): void {
157	    if (this.auth.isLoggedIn()) {
158	      this.navigateToDashboard();
159	    }
160	  }
161	
162	  clearError(): void {
163	    this.errorMessage = '';
164	  }
165	
166	  async onSubmit(): Promise<void> {
167	    this.loading = true;
168	    this.errorMessage = '';
169	
170	    try {
171	      const result = await this.auth.login(this.username, this.password);
172	      if (result.success) {
173	        this.navigateToDashboard();
174	      } else {
175	        this.errorMessage = result.error ?? 'Invalid username or password';
176	      }
177	    } finally {
178	      this.loading = false;
179	    }
180	  }
181	
182	  private navigateToDashboard(): void {
183	    const role = this.auth.getCurrentRole();
184	    switch (role) {
