export class RolePickerComponent implements OnInit {
  username = '';
  password = '';
  showPassword = false;
  loading = false;
  errorMessage = '';

  // Forced password change state
  showPasswordChange = false;
  newPassword = '';
  confirmPassword = '';
  showNewPw = false;
  private savedPassword = ''; // the default password used to log in

  constructor(
    private auth: AuthService,
    private router: Router,
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) {
      this.navigateToDashboard();
    }
  }

  clearError(): void {
    this.errorMessage = '';
  }

  async onSubmit(): Promise<void> {
    this.loading = true;
    this.errorMessage = '';

    try {
      const result = await this.auth.login(this.username, this.password);
      if (result.success) {
        // Check if password change is required
        const state = this.auth.state$ as any;
        const current = state.value ?? state.getValue?.();
        if (current?.passwordChangeRequired) {
          this.savedPassword = this.password;
          this.showPasswordChange = true;
          this.password = '';
        } else {
          this.navigateToDashboard();
        }
      } else {
        this.errorMessage = result.error ?? 'Invalid username or password';
      }
    } finally {
      this.loading = false;
    }
  }

  async onChangePassword(): Promise<void> {
    if (this.newPassword.length < 10) {
      this.errorMessage = 'Password must be at least 10 characters';
      return;
    }
    if (this.newPassword !== this.confirmPassword) {
      this.errorMessage = 'Passwords do not match';
      return;
    }
    if (this.newPassword === this.savedPassword) {
      this.errorMessage = 'New password must be different from the default';
      return;
    }

    this.loading = true;
    this.errorMessage = '';

    try {
      const role = this.auth.getCurrentRole();
      if (!role) {
        this.errorMessage = 'Session expired. Please log in again.';
        this.showPasswordChange = false;
        return;
      }

      const ok = await this.auth.changePassword(role, this.savedPassword, this.newPassword);
      if (ok) {
        this.savedPassword = '';
        this.navigateToDashboard();
      } else {
        this.errorMessage = 'Password change failed. Please try again.';
      }
    } finally {
      this.loading = false;
    }
  }

  private navigateToDashboard(): void {
    const role = this.auth.getCurrentRole();
    switch (role) {
      case 'admin':      this.router.navigate(['/dashboard']); break;
      case 'resident':   this.router.navigate(['/my-profile']); break;
      case 'compliance': this.router.navigate(['/documents']); break;
      case 'analyst':    this.router.navigate(['/analytics']); break;
      default:           this.router.navigate(['/login']); break;
    }
  }
}"}

